    # and the path values chosen so far

    # Step 1: find minimum value overall
    min_val = min(grid[i][j] for i in range(n) for j in range(n))

    # Active cells: all cells with the minimum value (step 1)
    active = set()
    for i in range(n):
        for j in range(n):
            if grid[i][j] == min_val:
                active.add((i, j))

    path = [min_val]

    for step in range(k - 1):
        # Find minimum neighbor value reachable from any active cell
