def minPath(grid, k):
    n = len(grid)

    def get_neighbors(i, j):
        neighbors = []
        for di, dj in [(-1,0),(1,0),(0,-1),(0,1)]:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < n:
                neighbors.append(grid[ni][nj])
        return neighbors

    # For each cell, the best path of length k starting there is:
    # cell_val, min_neighbor, cell_val, min_neighbor, ...
    # because after choosing the starting cell, we greedily go to min neighbor,
    # then come back (since cell_val < min_neighbor would mean we prefer to return)
    # Actually we need to be careful: we pick the sequence that's lexicographically smallest

    # For each cell, compute the best repeating pair (a, b) where a = cell value, b = min neighbor
    # The path is [a, b, a, b, ...] of length k

    best_path = None

    for i in range(n):
        for j in range(n):
            a = grid[i][j]
            neighbors = get_neighbors(i, j)
            b = min(neighbors)

            # Build path of length k alternating a, b
            path = []
            for step in range(k):
                if step % 2 == 0:
                    path.append(a)
                else:
                    path.append(b)

            if best_path is None or path < best_path:
                best_path = path

    return best_path

